# solution.py

"""
LanguageCollaborator - A collaborative language learning platform.

Facilitates collaborative learning among multiple users by providing
interactive language exercises, real-time feedback, and peer review capabilities.
"""

import hashlib
import secrets
import threading
import time
import uuid
from datetime import datetime, timedelta
from enum import Enum
from typing import Any, Dict, List, Optional, Tuple


# --- Enums ---

class ExerciseType(Enum):
    GRAMMAR_QUIZ = "grammar_quiz"
    VOCABULARY_TEST = "vocabulary_test"
    WRITING_PROMPT = "writing_prompt"


class FeedbackType(Enum):
    CORRECT = "correct"
    INCORRECT = "incorrect"
    SUGGESTION = "suggestion"
    GRAMMAR_ERROR = "grammar_error"
    VOCABULARY_SUGGESTION = "vocabulary_suggestion"


class UserRole(Enum):
    LEARNER = "learner"
    INSTRUCTOR = "instructor"
    ADMIN = "admin"


# --- Models ---

class User:
    """Represents a user in the system."""

    def __init__(self, username: str, password: str, role: UserRole = UserRole.LEARNER):
        self.id = str(uuid.uuid4())
        self.username = username
        self.password_hash = self._hash_password(password)
        self.role = role
        self.created_at = datetime.now()
        self.is_active = True
        self.session_token: Optional[str] = None

    @staticmethod
    def _hash_password(password: str) -> str:
        salt = "lang_collab_salt_v1"
        return hashlib.sha256(f"{salt}{password}".encode()).hexdigest()

    def verify_password(self, password: str) -> bool:
        return self.password_hash == self._hash_password(password)

    def generate_session_token(self) -> str:
        self.session_token = secrets.token_hex(32)
        return self.session_token


class Exercise:
    """Represents a language exercise."""

    def __init__(self, creator_id: str, exercise_type: ExerciseType,
                 title: str, content: Dict[str, Any]):
        self.id = str(uuid.uuid4())
        self.creator_id = creator_id
        self.exercise_type = exercise_type
        self.title = title
        self.content = content
        self.created_at = datetime.now()
        self.shared_with: List[str] = []
        self.is_public = False
        self.reviews: List["PeerReview"] = []

    def share_with_user(self, user_id: str):
        if user_id not in self.shared_with:
            self.shared_with.append(user_id)

    def make_public(self):
        self.is_public = True

    def is_accessible_by(self, user_id: str) -> bool:
        return (self.creator_id == user_id or
                user_id in self.shared_with or
                self.is_public)


class PeerReview:
    """Represents a peer review on an exercise."""

    def __init__(self, reviewer_id: str, exercise_id: str,
                 rating: int, comment: str):
        if not 1 <= rating <= 5:
            raise ValueError("Rating must be between 1 and 5")
        self.id = str(uuid.uuid4())
        self.reviewer_id = reviewer_id
        self.exercise_id = exercise_id
        self.rating = rating
        self.comment = comment
        self.created_at = datetime.now()


class ExerciseSubmission:
    """Represents a user's submission/answer to an exercise."""

    def __init__(self, user_id: str, exercise_id: str, answers: Any):
        self.id = str(uuid.uuid4())
        self.user_id = user_id
        self.exercise_id = exercise_id
        self.answers = answers
        self.submitted_at = datetime.now()
        self.feedback: List[Dict[str, Any]] = []
        self.score: Optional[float] = None


# --- Feedback Engine ---

class FeedbackEngine:
    """Provides real-time feedback on exercise submissions."""

    COMMON_GRAMMAR_ERRORS = {
        "their/there/they're": ["their", "there", "they're"],
        "its/it's": ["its", "it's"],
        "your/you're": ["your", "you're"],
        "affect/effect": ["affect", "effect"],
        "then/than": ["then", "than"],
    }

    VOCABULARY_SUGGESTIONS = {
        "good": ["excellent", "outstanding", "superb", "commendable"],
        "bad": ["poor", "inadequate", "substandard", "unsatisfactory"],
        "big": ["enormous", "substantial", "considerable", "vast"],
        "small": ["tiny", "diminutive", "minute", "compact"],
        "happy": ["elated", "delighted", "ecstatic", "jubilant"],
        "sad": ["melancholy", "sorrowful", "despondent", "forlorn"],
        "fast": ["rapid", "swift", "expeditious", "brisk"],
        "slow": ["sluggish", "gradual", "leisurely", "unhurried"],
    }

    def evaluate_grammar_quiz(self, exercise: Exercise,
                              submission: ExerciseSubmission) -> List[Dict[str, Any]]:
        """Evaluate answers for a grammar quiz."""
        feedback = []
        correct_answers = exercise.content.get("answers", [])
        user_answers = submission.answers

        if not isinstance(user_answers, list):
            return [{"type": FeedbackType.INCORRECT.value,
                     "message": "Invalid submission format"}]

        correct_count = 0
        total = len(correct_answers)

        for i, correct in enumerate(correct_answers):
            if i < len(user_answers):
                user_answer = user_answers[i]
                if str(user_answer).strip().lower() == str(correct).strip().lower():
                    feedback.append({
                        "question_index": i,
                        "type": FeedbackType.CORRECT.value,
                        "message": f"Question {i + 1}: Correct!"
                    })
                    correct_count += 1
                else:
                    feedback.append({
                        "question_index": i,
                        "type": FeedbackType.INCORRECT.value,
                        "message": f"Question {i + 1}: Incorrect. "
                                   f"Expected '{correct}', got '{user_answer}'."
                    })
            else:
                feedback.append({
                    "question_index": i,
                    "type": FeedbackType.INCORRECT.value,
                    "message": f"Question {i + 1}: Not answered."
                })

        submission.score = (correct_count / total * 100) if total > 0 else 0
        submission.feedback = feedback
        return feedback

    def evaluate_vocabulary_test(self, exercise: Exercise,
                                 submission: ExerciseSubmission) -> List[Dict[str, Any]]:
        """Evaluate answers for a vocabulary test."""
        feedback = []
        word_pairs = exercise.content.get("word_pairs", {})
        user_answers = submission.answers

        if not isinstance(user_answers, dict):
            return [{"type": FeedbackType.INCORRECT.value,
                     "message": "Invalid submission format"}]

        correct_count = 0
        total = len(word_pairs)

        for word, correct_definition in word_pairs.items():
            user_definition = user_answers.get(word, "")
            if str(user_definition).strip().lower() == str(correct_definition).strip().lower():
                feedback.append({
                    "word": word,
                    "type": FeedbackType.CORRECT.value,
                    "message": f"'{word}': Correct!"
                })
                correct_count += 1
            else:
                feedback.append({
                    "word": word,
                    "type": FeedbackType.INCORRECT.value,
                    "message": f"'{word}': Incorrect. Expected '{correct_definition}'."
                })

        submission.score = (correct_count / total * 100) if total > 0 else 0
        submission.feedback = feedback
        return feedback

    def evaluate_writing_prompt(self, exercise: Exercise,
                                submission: ExerciseSubmission) -> List[Dict[str, Any]]:
        """Evaluate a writing prompt submission with grammar and vocabulary suggestions."""
        feedback = []
        text = submission.answers if isinstance(submission.answers, str) else ""

        if not text.strip():
            return [{"type": FeedbackType.INCORRECT.value,
                     "message": "Empty submission"}]

        # Check grammar
        grammar_feedback = self._check_grammar(text)
        feedback.extend(grammar_feedback)

        # Vocabulary suggestions
        vocab_feedback = self._suggest_vocabulary(text)
        feedback.extend(vocab_feedback)

        # Basic structural feedback
        sentences = [s.strip() for s in text.split('.') if s.strip()]
        word_count = len(text.split())

        min_words = exercise.content.get("min_words", 50)
        if word_count < min_words:
            feedback.append({
                "type": FeedbackType.SUGGESTION.value,
                "message": f"Your response has {word_count} words. "
                           f"Try to write at least {min_words} words."
            })

        if len(sentences) < 3:
            feedback.append({
                "type": FeedbackType.SUGGESTION.value,
                "message": "Consider developing your ideas with more sentences."
            })

        # Score based on word count meeting and feedback severity
        errors = sum(1 for f in feedback
                     if f["type"] in [FeedbackType.GRAMMAR_ERROR.value,
                                      FeedbackType.INCORRECT.value])
        base_score = 100
        penalty = min(errors * 10, 50)
        length_factor = min(word_count / min_words, 1.0) if min_words > 0 else 1.0
        submission.score = max(0, (base_score - penalty) * length_factor)
        submission.feedback = feedback
        return feedback

    def _check_grammar(self, text: str) -> List[Dict[str, Any]]:
        """Basic grammar checking."""
        feedback = []
        words = text.split()

        # Check sentence capitalization
        sentences = text.split('.')
        for i, sentence in enumerate(sentences):
            stripped = sentence.strip()
            if stripped and not stripped[0].isupper():
                feedback.append({
                    "type": FeedbackType.GRAMMAR_ERROR.value,
                    "message": f"Sentence {i + 1} should start with a capital letter."
                })

        # Check double spaces
        if "  " in text:
            feedback.append({
                "type": FeedbackType.GRAMMAR_ERROR.value,
                "message": "Remove double spaces in your text."
            })

        # Check common errors
        text_lower = text.lower()
        if " i " in f" {text_lower} " and " I " not in f" {text} ":
            # Only flag if lowercase 'i' is used as pronoun
            for idx, word in enumerate(words):
                if word == "i" and (idx == 0 or words[idx - 1][-1] in '.!?'):
                    continue
                elif word == "i":
                    feedback.append({
                        "type": FeedbackType.GRAMMAR_ERROR.value,
                        "message": "The pronoun 'I' should always be capitalized."
                    })
                    break

        return feedback

    def _suggest_vocabulary(self, text: str) -> List[Dict[str, Any]]:
        """Suggest vocabulary improvements."""
        feedback = []
        words = text.lower().split()

        for word in words:
            clean_word = word.strip('.,!?;:"\'-()[]{}')
            if clean_word in self.VOCABULARY_SUGGESTIONS:
                alternatives = self.VOCABULARY_SUGGESTIONS[clean_word]
                feedback.append({
                    "type": FeedbackType.VOCABULARY_SUGGESTION.value,
                    "word": clean_word,
                    "message": f"Consider using a more precise word instead of "
                               f"'{clean_word}'. Suggestions: {', '.join(alternatives[:3])}"
                })

        return feedback

    def evaluate(self, exercise: Exercise,
                 submission: ExerciseSubmission) -> List[Dict[str, Any]]:
        """Route evaluation based on exercise type."""
        if exercise.exercise_type == ExerciseType.GRAMMAR_QUIZ:
            return self.evaluate_grammar_quiz(exercise, submission)
        elif exercise.exercise_type == ExerciseType.VOCABULARY_TEST:
            return self.evaluate_vocabulary_test(exercise, submission)
        elif exercise.exercise_type == ExerciseType.WRITING_PROMPT:
            return self.evaluate_writing_prompt(exercise, submission)
        else:
            return [{"type": "error", "message": "Unknown exercise type"}]


# --- Application Core ---

class LanguageCollaborator:
    """Main application class managing users, exercises, and collaboration."""

    def __init__(self):
        self._lock = threading.RLock()
        self._users: Dict[str, User] = {}
        self._sessions: Dict[str, str] = {}  # token -> user_id
        self._exercises: Dict[str, Exercise] = {}
        self._submissions: Dict[str, ExerciseSubmission] = {}
        self._feedback_engine = FeedbackEngine()

    # --- User Management ---

    def register_user(self, username: str, password: str,
                      role: UserRole = UserRole.LEARNER) -> Tuple[bool, str]:
        """Register a new user."""
        if not username or not password:
            return False, "Username and password are required"
        if len(username) < 3:
            return False, "Username must be at least 3 characters"
        if len(password) < 6:
            return False, "Password must be at least 6 characters"

        with self._lock:
            for user in self._users.values():
                if user.username == username:
                    return False, "Username already exists"

            user = User(username, password, role)
            self._users[user.id] = user
            return True, user.id

    def login(self, username: str, password: str) -> Tuple[bool, str]:
        """Authenticate a user and return a session token."""
        if not username or not password:
            return False, "Username and password are required"

        with self._lock:
            for user in self._users.values():
                if user.username == username:
                    if user.verify_password(password):
                        token = user.generate_session_token()
                        self._sessions[token] = user.id
                        return True, token
                    else:
                        return False, "Invalid password"
            return False, "User not found"

    def logout(self, token: str) -> bool:
        """Log out a user by invalidating their session."""
        with self._lock:
            if token in self._sessions:
                user_id = self._sessions[token]
                if user_id in self._users:
                    self._users[user_id].session_token = None
                del self._sessions[token]
                return True
            return False

    def get_user_by_token(self, token: str) -> Optional[User]:
        """Get user from session token."""
        with self._lock:
            user_id = self._sessions.get(token)
            if user_id:
                return self._users.get(user_id)
            return None

    def _authenticate(self, token: str) -> Optional[User]:
        """Internal authentication check."""
        return self.get_user_by_token(token)

    # --- Exercise Management ---

    def create_exercise(self, token: str, exercise_type: ExerciseType,
                        title: str, content: Dict[str, Any]) -> Tuple[bool, str]:
        """Create a new exercise."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        if not title or not title.strip():
            return False, "Title is required"
        if not content:
            return False, "Content is required"

        # Validate content based on type
        valid, msg = self._validate_exercise_content(exercise_type, content)
        if not valid:
            return False, msg

        with self._lock:
            exercise = Exercise(user.id, exercise_type, title.strip(), content)
            self._exercises[exercise.id] = exercise
            return True, exercise.id

    def _validate_exercise_content(self, exercise_type: ExerciseType,
                                   content: Dict[str, Any]) -> Tuple[bool, str]:
        """Validate exercise content structure."""
        if exercise_type == ExerciseType.GRAMMAR_QUIZ:
            if "questions" not in content or "answers" not in content:
                return False, "Grammar quiz requires 'questions' and 'answers'"
            if len(content["questions"]) != len(content["answers"]):
                return False, "Number of questions must match number of answers"
            if len(content["questions"]) == 0:
                return False, "Quiz must have at least one question"
        elif exercise_type == ExerciseType.VOCABULARY_TEST:
            if "word_pairs" not in content:
                return False, "Vocabulary test requires 'word_pairs'"
            if not isinstance(content["word_pairs"], dict):
                return False, "'word_pairs' must be a dictionary"
            if len(content["word_pairs"]) == 0:
                return False, "Vocabulary test must have at least one word pair"
        elif exercise_type == ExerciseType.WRITING_PROMPT:
            if "prompt" not in content:
                return False, "Writing prompt requires 'prompt' field"
            if not content["prompt"].strip():
                return False, "Prompt cannot be empty"
        return True, "Valid"

    def share_exercise(self, token: str, exercise_id: str,
                       target_user_id: str) -> Tuple[bool, str]:
        """Share an exercise with another user."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if exercise.creator_id != user.id:
                return False, "Only the creator can share an exercise"
            if target_user_id not in self._users:
                return False, "Target user not found"
            if target_user_id == user.id:
                return False, "Cannot share with yourself"

            exercise.share_with_user(target_user_id)
            return True, "Exercise shared successfully"

    def make_exercise_public(self, token: str,
                             exercise_id: str) -> Tuple[bool, str]:
        """Make an exercise publicly accessible."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if exercise.creator_id != user.id:
                return False, "Only the creator can make an exercise public"

            exercise.make_public()
            return True, "Exercise is now public"

    def get_exercise(self, token: str, exercise_id: str) -> Tuple[bool, Any]:
        """Get an exercise by ID (with access check)."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if not exercise.is_accessible_by(user.id):
                return False, "Access denied"
            return True, exercise

    def list_exercises(self, token: str,
                       only_own: bool = False) -> Tuple[bool, Any]:
        """List exercises accessible to the user."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            if only_own:
                exercises = [e for e in self._exercises.values()
                             if e.creator_id == user.id]
            else:
                exercises = [e for e in self._exercises.values()
                             if e.is_accessible_by(user.id)]
            return True, exercises

    # --- Submission & Feedback ---

    def submit_exercise(self, token: str, exercise_id: str,
                        answers: Any) -> Tuple[bool, Any]:
        """Submit answers for an exercise and get feedback."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if not exercise.is_accessible_by(user.id):
                return False, "Access denied"

            submission = ExerciseSubmission(user.id, exercise_id, answers)
            feedback = self._feedback_engine.evaluate(exercise, submission)
            self._submissions[submission.id] = submission

            return True, {
                "submission_id": submission.id,
                "score": submission.score,
                "feedback": feedback
            }

    def get_submission(self, token: str,
                       submission_id: str) -> Tuple[bool, Any]:
        """Get a submission by ID."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            submission = self._submissions.get(submission_id)
            if not submission:
                return False, "Submission not found"
            if submission.user_id != user.id:
                # Allow exercise creator to see submissions
                exercise = self._exercises.get(submission.exercise_id)
                if not exercise or exercise.creator_id != user.id:
                    return False, "Access denied"
            return True, submission

    # --- Peer Review ---

    def add_peer_review(self, token: str, exercise_id: str,
                        rating: int, comment: str) -> Tuple[bool, str]:
        """Add a peer review to an exercise."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        if not comment or not comment.strip():
            return False, "Review comment is required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if not exercise.is_accessible_by(user.id):
                return False, "Access denied"
            if exercise.creator_id == user.id:
                return False, "Cannot review your own exercise"

            try:
                review = PeerReview(user.id, exercise_id, rating, comment.strip())
            except ValueError as e:
                return False, str(e)

            exercise.reviews.append(review)
            return True, review.id

    def get_reviews(self, token: str,
                    exercise_id: str) -> Tuple[bool, Any]:
        """Get all reviews for an exercise."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if not exercise.is_accessible_by(user.id):
                return False, "Access denied"
            return True, exercise.reviews

    def get_average_rating(self, token: str,
                           exercise_id: str) -> Tuple[bool, Any]:
        """Get average rating for an exercise."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return False, "Exercise not found"
            if not exercise.is_accessible_by(user.id):
                return False, "Access denied"

            if not exercise.reviews:
                return True, {"average": None, "count": 0,
                              "message": "No reviews available"}

            ratings = [r.rating for r in exercise.reviews]
            avg = sum(ratings) / len(ratings)
            return True, {"average": round(avg, 2), "count": len(ratings)}

    # --- Statistics ---

    def get_user_stats(self, token: str) -> Tuple[bool, Any]:
        """Get statistics for the authenticated user."""
        user = self._authenticate(token)
        if not user:
            return False, "Authentication required"

        with self._lock:
            exercises_created = sum(
                1 for e in self._exercises.values()
                if e.creator_id == user.id
            )
            submissions_made = sum(
                1 for s in self._submissions.values()
                if s.user_id == user.id
            )
            reviews_given = sum(
                1 for e in self._exercises.values()
                for r in e.reviews if r.reviewer_id == user.id
            )
            avg_score = None
            user_submissions = [
                s for s in self._submissions.values()
                if s.user_id == user.id and s.score is not None
            ]
            if user_submissions:
                avg_score = round(
                    sum(s.score for s in user_submissions) / len(user_submissions), 2
                )

            return True, {
                "username": user.username,
                "exercises_created": exercises_created,
                "submissions_made": submissions_made,
                "reviews_given": reviews_given,
                "average_score": avg_score
            }


# --- Test Suite ---

def run_tests():
    """Comprehensive test suite for LanguageCollaborator."""
    passed = 0
    failed = 0
    errors = []

    def assert_true(condition, test_name):
        nonlocal passed, failed
        if condition:
            passed += 1
        else:
            failed += 1
            errors.append(f"FAILED: {test_name}")

    def assert_false(condition, test_name):
        assert_true(not condition, test_name)

    def assert_equal(actual, expected, test_name):
        nonlocal passed, failed
        if actual == expected:
            passed += 1
        else:
            failed += 1
            errors.append(f"FAILED: {test_name} - Expected {expected}, got {actual}")

    # ==========================================
    # TEST GROUP 1: User Registration & Login
    # ==========================================

    print("=" * 60)
    print("TEST GROUP 1: User Registration & Login")
    print("=" * 60)

    app = LanguageCollaborator()

    # Test: Register a user successfully
    success, user_id = app.register_user("alice", "password123")
    assert_true(success, "Register user 'alice'")
    assert_true(len(user_id) > 0, "User ID returned on registration")

    # Test: Register another user
    success, user_id2 = app.register_user("bob", "secure456")
    assert_true(success, "Register user 'bob'")

    # Test: Register third user
    success, user_id3 = app.register_user("charlie", "mypass789")
    assert_true(success, "Register user 'charlie'")

    # Test: Duplicate username
    success, msg = app.register_user("alice", "differentpass")
    assert_false(success, "Reject duplicate username")
    assert_equal(msg, "Username already exists", "Duplicate username message")

    # Test: Short username
    success, msg = app.register_user("ab", "password123")
    assert_false(success, "Reject short username")

    # Test: Short password
    success, msg = app.register_user("david", "12345")
    assert_false(success, "Reject short password")

    # Test: Empty credentials
    success, msg = app.register_user("", "password123")
    assert_false(success, "Reject empty username")
    success, msg = app.register_user("david", "")
    assert_false(success, "Reject empty password")

    # Test: Login successfully
    success, token_alice = app.login("alice", "password123")
    assert_true(success, "Login user 'alice'")
    assert_true(len(token_alice) > 0, "Token returned on login")

    # Test: Login another user
    success, token_bob = app.login("bob", "secure456")
    assert_true(success, "Login user 'bob'")

    # Test: Login third user
    success, token_charlie = app.login("charlie", "mypass789")
    assert_true(success, "Login user 'charlie'")

    # Test: Wrong password
    success, msg = app.login("alice", "wrongpass")
    assert_false(success, "Reject wrong password")
    assert_equal(msg, "Invalid password", "Wrong password message")

    # Test: Non-existent user login
    success, msg = app.login("nobody", "password123")
