    results_lock = threading.Lock()
    concurrent_results = {"registrations": 0, "logins": 0,
                          "exercises": 0, "submissions": 0}

    def register_users(start_idx, count):
        for i in range(count):
            s, _ = concurrent_app.register_user(
                f"user_{start_idx + i}", f"password_{start_idx + i}"
            )
            if s:
                with results_lock:
                    concurrent_results["registrations"] += 1

    def login_users(start_idx, count):
        for i in range(count):
            s, _ = concurrent_app.login(
                f"user_{start_idx + i}", f"password_{start_idx + i}"
            )
            if s:
                with results_lock:
                    concurrent_results["logins"] += 1

    # Register 20 users concurrently (4 threads x 5 users)
    threads = []
    for t in range(4):
        thread = threading.Thread(target=register_users, args=(t * 5, 5))
        threads.append(thread)
        thread.start()
    for thread in threads:
        thread.join()

    assert_equal(concurrent_results["registrations"], 20,
                 "20 concurrent registrations succeeded")

