    print(f"\n  PASSED: {passed}")
    print(f"  FAILED: {failed}")
    print(f"  Total:  {passed + failed}")
    print(f"  Rate:   {passed / (passed + failed) * 100:.1f}%\n")

    if errors:
        print("  Failures:")
        for err in errors:
            print(f"    - {err}")
    else:
        print("  All tests passed!")

    print("=" * 60)
    return failed == 0


